  ('h6_kettingregel', 'negatieve_macht_expressie', 5, 3, 'Schrijf terug: $f''(x) = -\dfrac{3}{(2x+1)\sqrt{2x+1}}$.'),
  ('h6_kettingregel', 'negatieve_macht_expressie', 6, 1, 'Schrijf om: $\dfrac{2}{\sqrt{x^2+4}} = 2(x^2+4)^{-\frac{1}{2}}$. Herken $v(x) = x^2+4$.'),
  ('h6_kettingregel', 'negatieve_macht_expressie', 6, 2, 'Bepaal $v''(x) = 2x$. Pas de kettingregel toe: $k''(x) = 2 \cdot (-\tfrac{1}{2})(x^2+4)^{-\frac{3}{2}} \cdot 2x = -2x(x^2+4)^{-\frac{3}{2}}$.'),
  ('h6_kettingregel', 'negatieve_macht_expressie', 6, 3, 'Schrijf terug: $k''(x) = -\dfrac{2x}{(x^2+4)\sqrt{x^2+4}}$.'),
  ('h6_combinaties', 'ketting_plus_product', 1, 1, 'Herken de productregel: $u(x) = x$ en $v(x) = \sqrt{2x+1} = (2x+1)^{\frac{1}{2}}$.'),
  ('h6_combinaties', 'ketting_plus_product', 1, 2, 'Bepaal $u''(x) = 1$ en $v''(x) = \tfrac{1}{2}(2x+1)^{-\frac{1}{2}} \cdot 2 = (2x+1)^{-\frac{1}{2}}$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_product', 1, 3, 'Pas de productregel toe: $f''(x) = 1 \cdot \sqrt{2x+1} + x \cdot \dfrac{1}{\sqrt{2x+1}} = \dfrac{(2x+1) + x}{\sqrt{2x+1}} = \dfrac{3x+1}{\sqrt{2x+1}}$.'),
  ('h6_combinaties', 'ketting_plus_product', 2, 1, 'Herken de productregel: $u(x) = x$ en $v(x) = (2x+1)^3$.'),
  ('h6_combinaties', 'ketting_plus_product', 2, 2, 'Bepaal $u''(x) = 1$ en $v''(x) = 3(2x+1)^2 \cdot 2 = 6(2x+1)^2$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_product', 2, 3, 'Pas de productregel toe: $f''(x) = (2x+1)^3 + x \cdot 6(2x+1)^2 = (2x+1)^3 + 6x(2x+1)^2$.'),
  ('h6_combinaties', 'ketting_plus_product', 3, 1, 'Herken de productregel: $u(x) = x$ en $v(x) = \sqrt{3x+1}$.'),
  ('h6_combinaties', 'ketting_plus_product', 3, 2, 'Bepaal $u''(x) = 1$ en $v''(x) = \dfrac{3}{2\sqrt{3x+1}}$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_product', 3, 3, 'Pas de productregel toe en vereenvoudig: $g''(x) = \sqrt{3x+1} + x \cdot \dfrac{3}{2\sqrt{3x+1}} = \dfrac{2(3x+1) + 3x}{2\sqrt{3x+1}} = \dfrac{9x+2}{2\sqrt{3x+1}}$.'),
  ('h6_combinaties', 'ketting_plus_product', 4, 1, 'Herken de productregel: $u(x) = x$ en $v(x) = (3x+1)^3$.'),
  ('h6_combinaties', 'ketting_plus_product', 4, 2, 'Bepaal $u''(x) = 1$ en $v''(x) = 3(3x+1)^2 \cdot 3 = 9(3x+1)^2$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_product', 4, 3, 'Pas de productregel toe: $h''(x) = (3x+1)^3 + x \cdot 9(3x+1)^2 = (3x+1)^3 + 9x(3x+1)^2$.'),
  ('h6_combinaties', 'ketting_plus_product', 5, 1, 'Herken de productregel: $u(x) = x^2$ en $v(x) = \sqrt{x+1} = (x+1)^{\frac{1}{2}}$.'),
  ('h6_combinaties', 'ketting_plus_product', 5, 2, 'Bepaal $u''(x) = 2x$ en $v''(x) = \dfrac{1}{2\sqrt{x+1}}$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_product', 5, 3, 'Pas de productregel toe: $f''(x) = 2x\sqrt{x+1} + x^2 \cdot \dfrac{1}{2\sqrt{x+1}}$.'),
  ('h6_combinaties', 'ketting_plus_product', 6, 1, 'Herken de productregel: $u(x) = x+1$ en $v(x) = (2x-1)^3$.'),
  ('h6_combinaties', 'ketting_plus_product', 6, 2, 'Bepaal $u''(x) = 1$ en $v''(x) = 3(2x-1)^2 \cdot 2 = 6(2x-1)^2$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_product', 6, 3, 'Pas de productregel toe: $k''(x) = (2x-1)^3 + (x+1) \cdot 6(2x-1)^2 = (2x-1)^3 + 6(x+1)(2x-1)^2$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 1, 1, 'Benoem teller en noemer: $t(x) = x+6$ en $n(x) = \sqrt{8x+9} = (8x+9)^{\frac{1}{2}}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 1, 2, 'Bepaal $t''(x) = 1$ en $n''(x) = \dfrac{8}{2\sqrt{8x+9}} = \dfrac{4}{\sqrt{8x+9}}$ (kettingregel). Pas de quotiëntregel toe.'),
  ('h6_combinaties', 'ketting_plus_quotient', 1, 3, 'Vereenvoudig de teller: $\dfrac{\sqrt{8x+9} - (x+6) \cdot \frac{4}{\sqrt{8x+9}}}{8x+9} = \dfrac{(8x+9) - 4(x+6)}{(8x+9)\sqrt{8x+9}} = \dfrac{4x-15}{(8x+9)\sqrt{8x+9}}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 2, 1, 'Benoem: $t(x) = x$ en $n(x) = \sqrt{2x+1} = (2x+1)^{\frac{1}{2}}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 2, 2, 'Bepaal $t''(x) = 1$ en $n''(x) = \dfrac{1}{\sqrt{2x+1}}$ (kettingregel). Pas de quotiëntregel toe.'),
  ('h6_combinaties', 'ketting_plus_quotient', 2, 3, 'Vereenvoudig: $\dfrac{\sqrt{2x+1} - x \cdot \frac{1}{\sqrt{2x+1}}}{2x+1} = \dfrac{(2x+1) - x}{(2x+1)\sqrt{2x+1}} = \dfrac{x+1}{(2x+1)\sqrt{2x+1}}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 3, 1, 'Benoem: $t(x) = \sqrt{x^2+1}$ en $n(x) = 2x+1$. Bepaal $t''(x) = \dfrac{x}{\sqrt{x^2+1}}$ (kettingregel) en $n''(x) = 2$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 3, 2, 'Pas de quotiëntregel toe: $g''(x) = \dfrac{\frac{x}{\sqrt{x^2+1}} \cdot (2x+1) - \sqrt{x^2+1} \cdot 2}{(2x+1)^2}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 3, 3, 'Laat de breuk in deze vorm staan — verdere vereenvoudiging is mogelijk maar niet vereist.'),
  ('h6_combinaties', 'ketting_plus_quotient', 4, 1, 'Benoem: $t(x) = x^2-1$ en $n(x) = \sqrt{4x+1}$. Bepaal $t''(x) = 2x$ en $n''(x) = \dfrac{2}{\sqrt{4x+1}}$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_quotient', 4, 2, 'Pas de quotiëntregel toe: $h''(x) = \dfrac{2x\sqrt{4x+1} - (x^2-1) \cdot \frac{2}{\sqrt{4x+1}}}{4x+1}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 4, 3, 'Laat in deze vorm staan.'),
  ('h6_combinaties', 'ketting_plus_quotient', 5, 1, 'Benoem: $t(x) = (2x+1)^2$ en $n(x) = x+1$. Bepaal $t''(x) = 2(2x+1) \cdot 2 = 4(2x+1)$ (kettingregel) en $n''(x) = 1$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 5, 2, 'Pas de quotiëntregel toe: $f''(x) = \dfrac{4(2x+1)(x+1) - (2x+1)^2}{(x+1)^2}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 5, 3, 'Laat in deze gefactoriseerde vorm staan.'),
  ('h6_combinaties', 'ketting_plus_quotient', 6, 1, 'Benoem: $t(x) = x^2+1$ en $n(x) = (3x-2)^2$. Bepaal $t''(x) = 2x$ en $n''(x) = 2(3x-2) \cdot 3 = 6(3x-2)$ (kettingregel).'),
  ('h6_combinaties', 'ketting_plus_quotient', 6, 2, 'Pas de quotiëntregel toe: $k''(x) = \dfrac{2x(3x-2)^2 - (x^2+1) \cdot 6(3x-2)}{(3x-2)^4}$.'),
  ('h6_combinaties', 'ketting_plus_quotient', 6, 3, 'Laat in deze vorm staan.')
) AS s(topic_slug, cluster_slug, q_order, step_order, description)
JOIN public.topics_new t          ON t.slug    = s.topic_slug
JOIN public.topic_clusters_new tc ON tc.slug   = s.cluster_slug AND tc.topic_id = t.id
JOIN public.questions_new q       ON q.cluster_id = tc.id AND q.order_index = s.q_order;

-- Validatie
SELECT 'question_steps_new' AS tbl, COUNT(*)::text AS n FROM public.question_steps_new;
-- Verwacht: 184 (H2) + 198 (H6) = 382

COMMIT;
